Here's how to handle each scenario with modern MSTest (3.9+/3.10+):

```csharp
[TestClass]
public sealed class AdvancedScenarioTests
{
    private readonly TestContext _testContext;
    private string? _tempFile;

    public AdvancedScenarioTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only (skipped on Linux/macOS)
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsInstallPath()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\MyApp", "InstallDir", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_UsesGpuAcceleration()
    {
        var renderer = new GpuRenderer();
        var frame = renderer.Render();
        Assert.IsNotNull(frame);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task GetWeather_ReturnsTemperature()
    {
        var client = new WeatherClient();
        var result = await client.GetCurrentAsync("Seattle", _testContext.CancellationToken);
        Assert.IsNotNull(result.Temperature);
    }

    // 4. Temp file cleanup — [TestCleanup] runs even on failure
    [TestMethod]
    public void Export_WritesToTempFile()
    {
        _tempFile = Path.GetTempFileName();
        var exporter = new DataExporter();

        exporter.Export(_tempFile);

        Assert.IsNotEmpty(File.ReadAllText(_tempFile));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
        {
            File.Delete(_tempFile);
        }
    }
}
```

**Key points:**

| Scenario | Attribute/Pattern | MSTest version |
|----------|-------------------|----------------|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky retry | `[Retry(3)]` | 3.9+ |
| Guaranteed cleanup | `[TestCleanup]` | All versions |

`[TestCleanup]` always runs after each test (even on failure), making it ideal for resource cleanup. For async cleanup, use `IAsyncDisposable` on the test class instead.
